#include <stdio.h>
#include <string.h>

int main() {
    char s1[] = "apple";
    char s2[] = "banana";
    int result = strcmp(s1, s2);
    if (result < 0) {
        printf("%s comes first\n", s1);
    } else if (result > 0) {
        printf("%s comes first\n", s2);
    } else {
        printf("Strings are equal\n");
    }
    return 0;
}
